```class Solution {
public:
    string reformatNumber(string number) {
        string result;
        for (char c : number) {
            if (c == ' ' || c == '-') continue;
            result += c;
        }
        string temp;
        for (char c : result) {
            temp += c;
            if (temp.length() == 3) {
                result += '-';
                temp = "";
            }
        }
        if (temp.length() > 0) {
            if (temp.length() == 2) result += '-' + temp;
            else result += temp;
        }
        return result;
    }
};```
